 1→import { buildApplication, buildRouteMap } from "@stricli/core";
 2→import { disableCommand } from "./commands/disable.js";
 3→import { enableCommand } from "./commands/enable.js";
 4→import { hooksRouteMap } from "./commands/hooks/index.js";
 5→import { loginCommand } from "./commands/login.js";
 6→import { logoutCommand } from "./commands/logout.js";
 7→import { setOrgCommand } from "./commands/set-org.js";
 8→import { uploadCommand } from "./commands/upload.js";
 9→import { whoamiCommand } from "./commands/whoami.js";
10→
11→const routes = buildRouteMap({
12→	routes: {
13→		login: loginCommand,
14→		logout: logoutCommand,
15→		whoami: whoamiCommand,
16→		upload: uploadCommand,
17→		enable: enableCommand,
18→		disable: disableCommand,
19→		"set-org": setOrgCommand,
20→		hooks: hooksRouteMap,
